    {"Course", rfl::type<Course>()},
    {"Score", rfl::type<Score>()},
    {"Major", rfl::type<Major>()}
};

// Table to primary key mapping: {table_name, {primary_key_column_name, primary_key_type}}
std::map<std::string, std::pair<std::string, Type> table_to_primary_key = {
    {"Student", {"SNo", sqlgen::Varchar<10>{} }}, // Type is Varchar<10>
    {"Course", {"CID", uint32_t{} }},             // Type is uint32_t
    {"Score", {"ScID", uint32_t{} }},             // Type is uint32_t
    {"Major", {"MID", uint32_t{} }}              // Type is uint32_t
};

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();
  // Insert the records
  auto result = sqlgen::insert(conn, records);
  // Check for errors? The problem does not specify error handling.
}

void modify_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id,
                              const std::string& col_name,
                              const dynamic::Value& new_value) {
  // Get the primary key information
  auto [pk_name, pk_type] = table_to_primary_key[table_name];

  dynamic::Value condition_value;
  if (table_name == "Student") {
    // Primary key is a string, but record_id is a string in the function signature?
    // We assume that the function signature is incorrect and should take a string for Student.
    condition_value = dynamic::Value{.str = record_id};
  } else {
    // Primary key is an integer
    condition_value = dynamic::Value{.int64 = std::stoll(record_id)};
  }

  // Form the condition: pk_name = condition_value
  auto condition = sqlgen::where(conditions::equal(
      sqlgen::col(pk_name), condition_value));

  // Form the set clause: col_name = new_value
  auto set_clause = sqlgen::set(sqlgen::col(col_name), new_value);

  // Build the update statement
  auto update_stmt = sqlgen::update(table_to_struct[table_name]) | condition | set_clause;

  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Execute the update
  auto result = update_stmt(conn);

  // Check for errors? The problem does not specify.
}

void delete_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id) {
  // Get the primary key information
  auto [pk_name, pk_type] = table_to_primary_key[table_name];

  dynamic::Value condition_value;
  if (table_name == "Student") {
    condition_value = dynamic::Value{.str = record_id};
  } else {
    condition_value = dynamic::Value{.int64 = std::stoll(record_id)};
  }

  // Form the condition: pk_name = condition_value
  auto condition = sqlgen::where(conditions::equal(
      sqlgen::col(pk_name), condition_value));

  // Build the delete statement
  auto delete_stmt = sqlgen::delete_from(table_to_struct[table_name]) | condition;

  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Execute the delete
  auto result = delete_stmt(conn);

  // Check for errors? The problem does not specify.
}
