 * Function: Calculate enrollment statistics per course.
 * 
 * @return List of course statistics
 */
std::vector<CourseStats> query_course_enrollment_stats() {
  // 1. Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // 2. Create tables with if_not_exists flag
  auto create_course = sqlgen::create_table<Course> | sqlgen::if_not_exists;
  auto create_enrollment = sqlgen::create_table<Enrollment> | sqlgen::if_not_exists;

  conn->execute(conn->to_sql(create_course));
  conn->execute(conn->to_sql(create_enrollment));

  // 3. Build the query using sqlgen's fluent interface
  using namespace sqlgen::literals;

  auto query = sqlgen::select_from<Course>(
      "title"_c, 
      sqlgen::count("enrollment_id"_c).as("student_count"), 
      sqlgen::avg("grade"_c).as("avg_grade")
