#include <gtest/gtest.h>

#include "query_product_sales_report.hpp"

namespace query_product_sales_report {

TEST(sqlite, query_product_sales_report) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  auto conn = sqlite::connect("test_db.sqlite").value();
  drop<Sale>(conn);
  drop<Product>(conn);
  create_table<Product>(conn);
  create_table<Sale>(conn);

  // Categories: A, B; A should pass HAVING (>5000), B should not
  Product pa{.product_id = 1, .category = "A"};
  Product pb{.product_id = 2, .category = "B"};
  insert(conn, std::vector{pa, pb});

  // Sales: A total amount 6000 (qty 10 + 20), B total amount 4000 (qty 5)
  Sale s1{.sale_id = 1, .product_id = 1, .quantity = 10, .amount = 2000.0};
  Sale s2{.sale_id = 2, .product_id = 1, .quantity = 20, .amount = 4000.0};
  Sale s3{.sale_id = 3, .product_id = 2, .quantity = 5, .amount = 4000.0};
  insert(conn, std::vector{s1, s2, s3});

  auto res = query_product_sales_report();

  ASSERT_EQ(res.size(), 1);
  EXPECT_EQ(res[0].category, "A");
  EXPECT_EQ(res[0].total_qty, 30);
  EXPECT_EQ(res[0].total_amt, 6000.0);
}

}  // namespace query_product_sales_report

