  using namespace sqlgen::literals;

  auto conn = sqlite::connect("test_db.sqlite").value();

  const auto query =
      select_from<Order, "o">(col<"order_id", "o"> | as<"order_id">,
                              col<"customer", "o"> | as<"customer">,
